    long long maxPrime = -1;
    // Divide n by 2 as long as it's even
    while (n % 2 == 0)
    {
        maxPrime = 2;
        n >>= 1; // Equivalent to n /= 2;
    }
    // Now n is odd, so we can skip all even factors
    for (long long i = 3; i <= sqrt(n); i += 2)
    {
        while (n % i == 0)
        {
            maxPrime = i;
            n /= i;
        }
    }
